from __future__ import annotations


STUDIO_HTML = r'''<!doctype html>
<html lang="ja">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Glyph Studio</title>
<style>
:root{color-scheme:dark;--bg:#101218;--panel:#191d25;--line:#303744;--text:#edf1f7;--muted:#98a2b3;--ok:#62d7a5;--bad:#ff7d8e;--accent:#8aa9ff}
*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:14px/1.45 ui-sans-serif,system-ui,sans-serif;height:100vh;overflow:hidden}
header{height:58px;display:flex;align-items:center;gap:14px;padding:0 18px;border-bottom:1px solid var(--line);background:#14171e}.brand{font-weight:760;font-size:17px}.path{color:var(--muted);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1}.status{padding:5px 9px;border-radius:999px;background:#252b36}.status.ready{color:var(--ok)}.status.error{color:var(--bad)}
button{border:1px solid var(--line);background:#252b36;color:var(--text);border-radius:7px;padding:7px 11px;cursor:pointer}button.primary{background:#3659a8;border-color:#5579d2}button:hover{filter:brightness(1.12)}
main{height:calc(100vh - 58px);display:grid;grid-template-columns:minmax(350px,46%) 1fr}.editor-pane{border-right:1px solid var(--line);display:flex;flex-direction:column;min-width:0}.pane-title{height:42px;padding:11px 14px;color:var(--muted);border-bottom:1px solid var(--line)}textarea{flex:1;width:100%;resize:none;border:0;outline:0;background:#0f1116;color:#e7ecf4;padding:16px;font:13px/1.55 ui-monospace,SFMono-Regular,Menlo,monospace;tab-size:2}
.viewer{min-width:0;display:flex;flex-direction:column}.tabs{height:42px;display:flex;gap:2px;padding:5px 8px;border-bottom:1px solid var(--line);overflow-x:auto}.tab{background:transparent;border:0;color:var(--muted);white-space:nowrap}.tab.active{color:var(--text);background:#252b36}.content{flex:1;overflow:auto;padding:18px}.cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px}.card{background:var(--panel);border:1px solid var(--line);border-radius:9px;padding:13px}.value{font-size:24px;font-weight:700}.label,.muted{color:var(--muted)}
pre{white-space:pre-wrap;word-break:break-word;background:#0f1116;border:1px solid var(--line);border-radius:8px;padding:14px;font:12px/1.55 ui-monospace,SFMono-Regular,Menlo,monospace}.error{border:1px solid #743844;background:#26171b;color:#ffc2ca;padding:12px;border-radius:8px;margin-bottom:12px}.edge{display:grid;grid-template-columns:minmax(120px,1fr) 36px minmax(120px,1fr) 90px;gap:8px;padding:8px;border-bottom:1px solid var(--line)}.component{border-left:3px solid var(--accent)}.component.effect{border-left-color:var(--bad)}.component.external{border-left-color:var(--muted)}.component.data{border-left-color:var(--ok)}.symbol{display:grid;grid-template-columns:50px 120px 1fr 1fr;gap:9px;padding:7px;border-bottom:1px solid var(--line)}h2{font-size:16px;margin:5px 0 12px}h3{font-size:14px;margin:18px 0 8px}
</style>
</head>
<body>
<header><div class="brand">Glyph Studio</div><div id="path" class="path"></div><div id="status" class="status">starting</div><button id="rebuild">Rebuild</button><button id="save" class="primary">Save</button></header>
<main><section class="editor-pane"><div class="pane-title">Source</div><textarea id="editor" spellcheck="false"></textarea></section><section class="viewer"><nav id="tabs" class="tabs"></nav><div id="content" class="content"></div></section></main>
<script>
const tabs=['Overview','Architecture','State','Logic','Time','Rust','Host','AST','Symbols','Artifacts'];let active='Overview',state=null,dirty=false,lastVersion=-1;
const editor=document.getElementById('editor'),content=document.getElementById('content');editor.addEventListener('input',()=>dirty=true);
document.getElementById('save').onclick=async()=>{await post('/api/save',{source:editor.value});dirty=false;await refresh(true)};document.getElementById('rebuild').onclick=async()=>{await post('/api/rebuild',{});await refresh(true)};
function esc(x){return String(x??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
async function post(url,body){return fetch(url,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)})}
async function artifact(name){const r=await fetch('/api/artifact?name='+encodeURIComponent(name));const x=await r.json();return x.content||''}
function makeTabs(){document.getElementById('tabs').innerHTML=tabs.map(t=>`<button class="tab ${t===active?'active':''}" data-t="${t}">${t}</button>`).join('');document.querySelectorAll('.tab').forEach(b=>b.onclick=()=>{active=b.dataset.t;makeTabs();render()})}
function diagnostics(){return (state.diagnostics||[]).map(d=>`<div class="error">${esc(d.message)}</div>`).join('')}
function overview(){const ir=state.execution_ir||{},sem=state.semantic||{};return diagnostics()+`<div class="cards"><div class="card"><div class="value">${(sem.functions||[]).length}</div><div class="label">Functions</div></div><div class="card"><div class="value">${(ir.machines||[]).length}</div><div class="label">Machines</div></div><div class="card"><div class="value">${(ir.temporal||[]).length}</div><div class="label">Time constraints</div></div><div class="card"><div class="value">${(sem.symbols||[]).length}</div><div class="label">Symbols</div></div></div><h3>Build</h3><pre>Status: ${esc(state.status)}\nUpdated: ${esc(state.updated_at)}\nDigest: ${esc((state.digest||'').slice(0,16))}\nOutput: ${esc(state.output_dir)}</pre>`}
async function architecture(){let data={systems:[]};try{data=JSON.parse(await artifact('architecture-ir.json'))}catch(_){ }const systems=data.systems||[];if(!systems.length)return '<div class="muted">system declaration is not present.</div>';return systems.map(s=>{const byId=Object.fromEntries((s.components||[]).map(c=>[c.id,c]));const cs=(s.components||[]).map(c=>`<div class="card component ${esc(c.kind)}"><b>${esc(c.name)}</b><div class="muted">${esc(c.kind)}${c.binding?' · '+esc(c.binding):''} · L${c.line}</div></div>`).join('');const es=(s.edges||[]).map(e=>`<div class="edge"><b>${esc(byId[e.source_id]?.name||e.source_id)}</b><span>→</span><b>${esc(byId[e.target_id]?.name||e.target_id)}</b><span class="muted">L${e.line}</span></div>`).join('');return `<h2>${esc(s.name)}</h2><div class="cards">${cs}</div><h3>Connections</h3>${es}`}).join('')}
function stateView(){const ms=state.execution_ir?.machines||[];if(!ms.length)return '<div class="muted">machine declaration is not present.</div>';return ms.map(m=>{const ts=(m.transitions||[]).map(t=>`<div class="edge"><b>${esc(t.source_state)}</b><span>→</span><b>${esc(t.target_state)}</b><span>${esc(t.condition)}</span></div>`).join('');return `<h2>${esc(m.name)}</h2><pre>initial: ${esc(m.initial_state)}\nsuccess: ${esc(m.success_state)}\nfailure: ${esc(m.failure_state)}</pre><h3>Transitions</h3>${ts}`}).join('')}
function logic(){const ir=state.execution_ir||{},nodes=ir.nodes||[],edges=ir.edges||[];return `<h2>Internal logic</h2><div class="cards">${nodes.map(n=>`<div class="card"><b>${esc(n.label)}</b><div class="muted">${esc(n.kind)} · L${n.source?.line||0}</div></div>`).join('')}</div><h3>Flow</h3>${edges.map(e=>`<div class="edge"><b>${esc(e.source_id)}</b><span>→</span><b>${esc(e.target_id)}</b><span>${esc(e.label||e.kind)}</span></div>`).join('')}`}
function timeView(){const xs=state.execution_ir?.temporal||[];return `<h2>Time and safety constraints</h2>${xs.map(x=>`<div class="card" style="margin-bottom:9px"><b>${esc(x.name)}</b><pre>${esc(x.formula)}</pre><div class="muted">${esc(x.streaming_monitor)}</div></div>`).join('')||'<div class="muted">No temporal constraints.</div>'}`}
async function code(name){content.innerHTML='<div class="muted">loading…</div>';content.innerHTML='<pre>'+esc(await artifact(name))+'</pre>'}
function ast(){return '<pre>'+esc(JSON.stringify(state.semantic||{},null,2))+'</pre>'}
function symbols(){return `<div class="symbol muted"><span>ID</span><span>Kind</span><span>Name</span><span>Type</span></div>${(state.semantic?.symbols||[]).map(s=>`<div class="symbol"><span>${s.id}</span><span>${esc(s.kind)}</span><b>${esc(s.name)}</b><span>${esc(s.type||'')}</span></div>`).join('')}`}
function artifacts(){return `<h2>Generated automatically</h2>${(state.artifact_names||[]).map(n=>`<div class="card" style="margin-bottom:8px"><b>${esc(n)}</b><div class="muted">${esc(state.output_dir+'/'+n)}</div></div>`).join('')}`}
async function render(){if(!state)return;document.getElementById('path').textContent=state.source_path;const st=document.getElementById('status');st.textContent=state.status;st.className='status '+state.status;if(active==='Overview')content.innerHTML=overview();else if(active==='Architecture')content.innerHTML=await architecture();else if(active==='State')content.innerHTML=stateView();else if(active==='Logic')content.innerHTML=logic();else if(active==='Time')content.innerHTML=timeView();else if(active==='Rust')code('generated.rs');else if(active==='Host')code('host.generated.rs');else if(active==='AST')content.innerHTML=ast();else if(active==='Symbols')content.innerHTML=symbols();else content.innerHTML=artifacts()}
async function refresh(force=false){const r=await fetch('/api/state',{cache:'no-store'});const next=await r.json();if(force||next.version!==lastVersion){state=next;lastVersion=next.version;if(!dirty)editor.value=state.source||'';await render()}}
makeTabs();refresh(true);setInterval(()=>refresh(false),600);
</script>
</body></html>'''
